var doc = Rhino.RhinoDoc.ActiveDoc;
var rng = new Random();
var ids = new List<Guid>();
for (int i = 0; i < 10; i++)
{
    var p = new Rhino.Geometry.Point3d(rng.NextDouble() * 1000, rng.NextDouble() * 1000, 0);
    ids.Add(doc.Objects.AddPoint(p));
}
int groupIndex = doc.Groups.Add(ids);
doc.Views.Redraw();
return new { group_index = groupIndex, point_count = ids.Count, ids = ids.ConvertAll(g => g.ToString()) };
